import{_ as r}from"./plugin-vue_export-helper-c27b6911.js";import{r as s,o as l,c as p,a as e,b as i,d as t,e as n}from"./app-46d6f74d.js";const d={},c=n('<p>如果你是新来的粉丝，你可能很疑惑，苏打绿为什么又叫「鱼丁糸」？</p><p>其实，鱼丁糸既是苏打绿，也不是苏打绿。</p><figure><img src="https://cdn.jsdelivr.net/gh/kaluojushi/sodaguide@picbed/start/sodagreen/oaeen-intro.jpg" alt="鱼丁糸" tabindex="0" loading="lazy"><figcaption>鱼丁糸</figcaption></figure><h2 id="「鱼丁糸」是怎么来的" tabindex="-1"><a class="header-anchor" href="#「鱼丁糸」是怎么来的" aria-hidden="true">#</a> 「鱼丁糸」是怎么来的？</h2><figure><img src="https://cdn.jsdelivr.net/gh/kaluojushi/sodaguide@picbed/start/sodagreen/oaeen-origin.jpg" alt="" width="300" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>「鱼丁糸」（yú dīng mì）来源于「苏打绿」的繁体「蘇打綠」的拆解。</p><p>苏打绿早期，当苏打绿化身为「鱼丁糸」时，吴青峰也会化身为「天月山」，同样拆解自吴青峰的名字。</p><h2 id="苏打绿时期" tabindex="-1"><a class="header-anchor" href="#苏打绿时期" aria-hidden="true">#</a> 苏打绿时期</h2><figure><img src="https://cdn.jsdelivr.net/gh/kaluojushi/sodaguide@picbed/start/sodagreen/oaeen-early.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>2005 年 6 月 17 日，苏打绿于女巫店表演时，以鱼丁糸的名字发行了《鱼丁糸首张专辑试听吸滴》，收录 9 首歌，全长约 7 分钟，为《OH OH OH OH! 夏天来听苏打绿乐团唱歌》试听单曲前身，专辑为纯手工压制。</p>',10),g={class:"hint-container tip"},h=n('<p class="hint-container-title">《鱼丁糸首张专辑试听吸滴》包含 9 首歌曲</p><p>每首歌大约 45 秒左右。</p><ol><li>〈后悔莫及〉（Demo 片段）</li><li>〈oh oh oh oh……〉（Demo 片段）</li><li>〈That Moment Is Over〉（Demo 片段）</li><li>〈是我的海〉（Demo 片段）</li><li>〈漂浮〉（Demo 片段）</li><li>〈频率〉（Demo 片段）</li><li>〈你喔！〉（Demo 片段）</li><li>〈降落练习存在孪生基因〉（Demo 片段）</li><li>〈相对论IV〉（Demo 片段）</li></ol>',3),u={href:"https://www.bilibili.com/video/av808753576",target:"_blank",rel:"noopener noreferrer"},_=e("p",null,"2005 年 7 月 15 日，苏打绿于台南海安路封街表演时，现场发行了《OH OH OH OH! 夏天来听苏打绿乐团唱歌》，内容以《鱼丁糸首张专辑试听吸滴》为蓝本，是《苏打绿》（同名专辑）的试听单曲，将 9 首歌曲压制为 1 支单曲。第一批现场发行的为纸壳版本，第二批为塑料壳版本。",-1),f=e("p",null,"2005 年 9 月 3 日，苏打绿发行第 1 张专辑《苏打绿》（同名专辑）。",-1),m={href:"https://www.bilibili.com/video/av11921562",target:"_blank",rel:"noopener noreferrer"},b={href:"https://www.bilibili.com/video/av28816945",target:"_blank",rel:"noopener noreferrer"},v=n('<div class="hint-container info"><p class="hint-container-title">为什么化名鱼丁糸登台？</p><p>2016 年是苏打绿第一次登上海洋音乐祭表演的 13 周年，大家为了回到起点，用首张单曲的团名再登音乐祭。</p><p>青峰在彩排直播上说登音乐祭的规则是寄出 Demo 来筛选，所以他们特意用鱼丁糸这个名字投了 Demo，最后还是被选中了。</p></div><h2 id="_2020-年出道" tabindex="-1"><a class="header-anchor" href="#_2020-年出道" aria-hidden="true">#</a> 2020 年出道</h2><p>2020 年 7 月 3 日，因陷入与前经纪人林暐哲的版权与商标权纠纷，苏打绿宣布以分身「鱼丁糸」（Oaeen）的名义出道。鼓手八女（小威）表示鱼丁糸的唯一指导原则是不能像苏打绿，透露将展现出与苏打绿完全不同的面貌。</p><figure><img src="https://cdn.jsdelivr.net/gh/kaluojushi/sodaguide@picbed/start/sodagreen/oaeen-start.jpg" alt="鱼丁糸正式出道" width="400" tabindex="0" loading="lazy"><figcaption>鱼丁糸正式出道</figcaption></figure><p>同时，团员们也取了全新的艺名，阿福是可田、家凯是豕豆、小威是八女、阿龚是金八、馨仪是香我、青峰是日出，各人拥有自己的代表符号。此外，粉丝称为「浮萍」，粉丝后援会成了「池堂」。</p><figure><img src="https://cdn.jsdelivr.net/gh/kaluojushi/sodaguide@picbed/start/sodagreen/oaeen-names.png" alt="团员们的艺名和符号" tabindex="0" loading="lazy"><figcaption>团员们的艺名和符号</figcaption></figure><div class="hint-container info"><p class="hint-container-title">团员们艺名的由来</p><ul><li>「可田」拆解自「阿福」</li><li>「豕豆」拆解自「家凯」的繁体「家凱」</li><li>「八女」拆解自「小威」</li><li>「金八」拆解自「钰祺」的繁体「鈺祺」</li><li>「香我」拆解自「馨仪」的繁体「馨儀」</li><li>「日出」拆解自「青峰」</li></ul><p>在〈在世界的尽头大声地说我恨你〉MV 中，团员们展示了艺名与原名的对应关系。</p><figure><img src="https://cdn.jsdelivr.net/gh/kaluojushi/sodaguide@picbed/start/sodagreen/oaeen-names-origin.png" alt="〈在世界的尽头大声地说我恨你〉MV" tabindex="0" loading="lazy"><figcaption>〈在世界的尽头大声地说我恨你〉MV</figcaption></figure></div>',7),j={class:"hint-container danger"},x=e("p",{class:"hint-container-title"},"注意！",-1),k=e("p",null,[i("鱼丁糸出道并不意味着 "),e("strong",null,"「苏打绿解散」"),i(" 或 "),e("strong",null,"「苏打绿改名鱼丁糸」"),i("，苏打绿仍然是苏打绿，鱼丁糸是苏打绿的分身。")],-1),E={href:"https://weibo.com/1822796164/JbEidwxU0",target:"_blank",rel:"noopener noreferrer"},w=n('<details class="hint-container details"><summary>青峰的微博</summary><p>大家好，我是吴青峰，身为同时认识「苏打绿」与「鱼丁糸」的朋友，有些话，我以旁观者的身份来跟大家说说。先帮大家划重点下结论，最近很常看到有人说「苏打绿改名鱼丁糸」，错！苏打绿没有改名，苏打绿还是叫苏打绿，「鱼丁糸」并不是苏打绿改的名字，而是一个分身，更好像是青梅竹马。</p><p>苏打绿和鱼丁糸是同期一起玩音乐长大的两个乐团，但苏打绿比较幸运，不像鱼丁糸熬了十五年才出道，比我熬得还久！一直以来，鱼丁糸都代表着，苏打绿任性的那一面，像是苏打绿首张专辑要做试听片的时候，就任性地借用了鱼丁糸的名字；又像是海洋音乐祭时，鱼丁糸就这样突然站上了小舞台。</p><p>苏打绿想要任性时，就会躲进鱼丁糸这个分身里。基本上，应该是要当作两个不同的乐团看待的。可以预见到时候很多人会拿鱼丁糸的音乐跟苏打绿比来比去，就像我个人出作品时，很多人就硬要跟打绿混为一谈，基本上应该要视为两个完全不同的单位，硬要放在一起，其实没啥意思。这些人的起手式通常是「身为打绿的十几年老粉⋯⋯」，这个起手式就先看出你评论跟聆听眼界的狭窄了，很多老粉看了应该也觉得，拜托你不要随便代表老粉好吗。好笑的是，有些人酸来呛去，嘴巴嚷嚷说讨厌看我solo，可是又口嫌体正直每个作品都买了一波，连个人代言抽奖都跑去参加，抽中了还要假高尚嫌弃说其实没有很想要啦，哎唷，要酸人也稍微有点品格，这种心口不一表里不一的酸法，素质实在很逗。</p><p>离题了，总之可想见，鱼丁糸又要迎来一波这样无意义的比较，两个不同的个体，有什么好比的。</p><p>人们常常说，我们要比较、要打败的，不是别人，是自己。要战胜的是自己⋯⋯错！就我看来，每一次有新作品时，这些人并没有在想「要战胜过去的自己」，上一张作品也很好，有什么好打败的？他们其实一直都是「忘掉以前的自己，管他的！」明明还有很多想做的啊，管那么多干嘛？做新作品时，前作就已经变成「别人」，与他们无关了。</p><p>好像旅游，上次去台东玩，这次想去伦敦走走，再来去北京看看，下次去柏林好了，然后玩来玩去，觉得台东很令人怀念，三不五时回去重游，重游又有新发现！然后，突然去南极探险，或去冰岛圆梦！难道会有什么，我「这次旅游一定要打败上次旅游」吗？</p><p>十年前我就说过，有人满嘴说着「你要做自己」，其实根本只容许别人做「他要的你」而已。同样的状况，越是自称老资格的，就越证明处在死胡同，每次都一样。最近实在非常深刻体验到只能活在过去的人，困扰自己也困扰别人的可怕。</p><p>偏偏不管我个人，或是打绿们，都是那种没有要待在原地的个性，所以打绿身为前辈，现在基于自己的经验警告鱼丁糸：「打绿出每一张专辑，因为都跟上一张专辑风格有差异，每一张都饱受批评，老是说『你变了你变了』的人，只是因为他们自己无法往前而已。但久而久之呢，也就习惯并无视了。现在鱼丁糸还没发声，想必已经有一堆『正义之士』拿好苏打绿的布袋要盖在你们头上，你们等着吧！」邪笑。</p><p>不过，幸好鱼丁糸本来就很任性，劝这些人还是早早收工吧，在那撑着也不会有便当喔！心疼呐～</p><p>写完之后，给日出过目，日出只说了句：「废话真多。」哈哈，废话多就是吴青峰的风格啊。</p><p>随文附赠十五年前，鱼丁糸三个字第一次登场。</p></details>',1),D=n('<p>2020 年 7 月 31 日，鱼丁糸在台北华山 Legacy 举办「Follow Me」演唱会，并在演唱会上公开演唱全新单曲〈沙发里有沙发 Radio〉，该单曲于 8 月 7 日 19:00 正式数位发行。</p><p>2021 年 9 月 17 日，鱼丁糸发行第 1 张专辑《池堂怪谈》。</p><h2 id="复刻计划" tabindex="-1"><a class="header-anchor" href="#复刻计划" aria-hidden="true">#</a> 复刻计划</h2><p>虽然吴青峰于 2021 年 4 月在版权官司上胜诉，但苏打绿原来歌曲的录音母带仍在前经纪人林暐哲手中。</p><p>2021 年 11 月，鱼丁糸宣布了「全新糸列 复刻计划」，将会把苏打绿时期的作品全部重新录制并发行，每张专辑采双 CD 形式，CD2 是一些过去从未发表过的歌曲（即苏打绿「In Summer」演唱会的翻唱录音）。</p><figure><img src="https://cdn.jsdelivr.net/gh/kaluojushi/sodaguide@picbed/start/sodagreen/oaeen-reproduce.jpeg" alt="鱼丁糸「全新糸列 复刻计划」" tabindex="0" loading="lazy"><figcaption>鱼丁糸「全新糸列 复刻计划」</figcaption></figure><p>2022 年至今，鱼丁糸已经发行了《鱼丁糸不同名专辑》《小宇宙（鱼版）》《无与伦比的美丽（鱼版）》《陪我歌唱（鱼版）》4 张复刻专辑。</p><p>2022 年 10 月 1 日，台湾智慧局宣布苏打绿商标将由苏打绿公司取得，为期两年的商标纠纷结束。2023 年 2 月 18 日，鱼丁糸于「池堂影夜」演唱会中，宣布夺回苏打绿团名，正式回归。</p>',8),y={class:"hint-container danger"},B=n('<p class="hint-container-title">注意！</p><p>虽然「苏打绿」的名字已由苏打绿取得，但原来的歌曲录音母带仍在前经纪人林暐哲手中。2023 年 3 月 4 日，吴青峰在 Facebook 发文呼吁大家，不要听苏打绿的歌。</p><figure><img src="https://cdn.jsdelivr.net/gh/kaluojushi/sodaguide@picbed/start/sodagreen/oaeen-don&#39;t-listen.jpeg" alt="" width="400" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>我们也在此呼吁各位新老打粉：</p><p><strong>请不要在各大音乐平台上（如 QQ 音乐、网易云音乐、Apple Music）收听苏打绿 2018 年以前的作品！</strong></p><p><strong>你的每一次收听都会给林暐哲带来收益！</strong></p><p><strong>请支持鱼丁糸的复刻专辑，并耐心等等他们接下来的复刻！</strong></p><p><strong>青峰推荐的收听苏打绿的方式：通过 CD 在有限范围内本地收听。</strong></p><p>我们为你推荐的收听方式：</p>',9),O={href:"/resources/music#%E8%8B%8F%E6%89%93%E7%BB%BF%E5%AE%98%E6%96%B9%E6%89%80%E5%8F%91%E8%A1%8C%E7%9A%84%E6%89%80%E6%9C%89%E6%AD%8C%E6%9B%B2-2004-2016"},z={href:"https://space.bilibili.com/390537041",target:"_blank",rel:"noopener noreferrer"};function H(V,C){const o=s("ExternalLinkIcon"),a=s("FontIcon");return l(),p("div",null,[c,e("div",g,[h,e("p",null,[i("如果你也想听，在这里试听："),e("a",u,[i("对市面上的不同版本进行对比_哔哩哔哩_bilibili"),t(o)])])]),_,f,e("p",null,[i("2016 年 7 月 24 日，苏打绿化名鱼丁糸在 "),e("a",m,[i("贡寮海洋音乐祭小舞台"),t(o)]),i(" 上表演了《苏打绿》（同名专辑）的 5 首歌。同日晚上在 "),e("a",b,[i("大舞台"),t(o)]),i("，苏打绿以自身名义进行表演。")]),v,e("div",j,[x,k,e("p",null,[i("2020 年 7 月 17 日，吴青峰发 "),e("a",E,[i("微博"),t(o)]),i(" 特意解释了这一点。")]),w]),D,e("div",y,[B,e("ul",null,[e("li",null,[e("a",O,[t(a,{icon:"resource"}),i(" 打绿资源库 / "),t(a,{icon:"music"}),i(" 音乐资源 / 苏打绿官方所发行的所有歌曲（2004-2016）")])]),e("li",null,[e("a",z,[i("B 站 up 主：苏打 bubble"),t(o)])])])])])}const M=r(d,[["render",H],["__file","oaeen.html.vue"]]);export{M as default};
